import type { EventEmitter } from "../../../execution/round_executor.js";
import type {
  CompilationFixTaskCompletedPayload,
  CompilationFixTaskStartedPayload,
  CompilationFixTaskStatusPayload,
  CompilationFixTaskType,
  CompilationFixTaskStatus,
} from "../../models.js";

type CommonContext = {
  sessionId: string;
  turnId: string;
  phaseId: "compilation_fix";
  roundNum: number;
  batchIndex: number;
  totalBatches: number;
};

export class TaskEventEmitter {
  private seq = 0;

  constructor(
    private readonly taskId: string,
    private readonly emit: EventEmitter,
    private readonly common: CommonContext,
  ) {}

  wrapAgenticEmitter(): EventEmitter {
    return (eventData) => {
      const payload = { ...(eventData.payload ?? {}) } as Record<string, unknown>;
      const rawRoundId = typeof payload.roundId === "string" ? payload.roundId : undefined;
      if (rawRoundId && !rawRoundId.startsWith("cf-task:")) {
        payload.roundId = `cf-task:${encodeURIComponent(this.taskId)}:${rawRoundId}`;
      }
      this.emit({
        ...eventData,
        payload: {
          ...payload,
          taskId: this.taskId,
        },
      });

      // IDE 桥接兜底：text-chunk 同步镜像到 spec-workflow task-status
      // 避免高频 agentic 事件在桥接层丢失导致分支面板正文缺失
      if (eventData.event === "agentic://text-chunk" && typeof payload.text === "string" && payload.text.length > 0) {
        const statusPayload: CompilationFixTaskStatusPayload = {
          ...this.basePayload(),
          status: "running",
          progress: undefined,
          message: payload.text,
        };
        this.emit({
          event: "spec-workflow://compilation-fix-task-status",
          payload: statusPayload as unknown as Record<string, unknown>,
        });
      }
    };
  }

  emitTaskStarted(input: {
    taskType: CompilationFixTaskType;
    taskName: string;
    description: string;
    errorCount: number;
    affectedFiles?: string[];
  }): void {
    const payload: CompilationFixTaskStartedPayload = {
      ...this.basePayload(),
      taskType: input.taskType,
      taskName: input.taskName,
      description: input.description,
      errorCount: input.errorCount,
      affectedFiles: input.affectedFiles,
    };
    this.emit({
      event: "spec-workflow://compilation-fix-task-started",
      payload: payload as unknown as Record<string, unknown>,
    });
  }

  emitTaskStatus(input: {
    status: CompilationFixTaskStatus;
    progress?: number;
    message?: string;
  }): void {
    const payload: CompilationFixTaskStatusPayload = {
      ...this.basePayload(),
      status: input.status,
      progress: input.progress,
      message: input.message,
    };
    this.emit({
      event: "spec-workflow://compilation-fix-task-status",
      payload: payload as unknown as Record<string, unknown>,
    });
  }

  emitTaskCompleted(input: {
    taskType: CompilationFixTaskType;
    success: boolean;
    fixedCount: number;
    remainingCount: number;
    durationMs: number;
    errorMessage?: string;
  }): void {
    const payload: CompilationFixTaskCompletedPayload = {
      ...this.basePayload(),
      taskType: input.taskType,
      success: input.success,
      fixedCount: input.fixedCount,
      remainingCount: input.remainingCount,
      durationMs: input.durationMs,
      errorMessage: input.errorMessage,
    };
    this.emit({
      event: "spec-workflow://compilation-fix-task-completed",
      payload: payload as unknown as Record<string, unknown>,
    });
  }

  private basePayload() {
    this.seq += 1;
    return {
      sessionId: this.common.sessionId,
      turnId: this.common.turnId,
      phaseId: this.common.phaseId,
      taskId: this.taskId,
      roundNum: this.common.roundNum,
      batchIndex: this.common.batchIndex,
      totalBatches: this.common.totalBatches,
      seq: this.seq,
      timestamp: Date.now(),
    };
  }
}
